// Helper functions for templates

func isArchitectPhaseCompleted(current models.ArchitectPhase, step models.ArchitectPhase) bool {
	phases := []models.ArchitectPhase{
		models.PhaseVisionRefinement,
		models.PhaseArchitecture,
		models.PhaseRiskAnalysis,
		models.PhasePhasing,
		models.PhaseDependencies,
		models.PhaseEstimation,
		models.PhaseReview,
		models.PhaseComplete,
	}
	currentIdx := -1
	stepIdx := -1
	for i, p := range phases {
		if p == current {
			currentIdx = i
		}
		if p == step {
			stepIdx = i
		}
	}
	return stepIdx < currentIdx
}

func hasArchitectPhaseTasks(tasks []models.ArchitectTask, phase models.ArchitectTaskPhase) bool {
	for _, t := range tasks {
		if t.Phase == phase {
			return true
		}
	}
	return false
}

func countArchitectPhaseTasks(tasks []models.ArchitectTask, phase models.ArchitectTaskPhase) int {
	count := 0
	for _, t := range tasks {
		if t.Phase == phase {
			count++
		}
	}
	return count
}

func totalArchitectEstHours(tasks []models.ArchitectTask) float64 {
	total := 0.0
	for _, t := range tasks {
		total += t.EstHours
	}
	return total
}

